def depth_max(s):
    depth = 0
    max_depth = 0
    for char in s:
        if char == '[':
            depth += 1
            max_depth = max(depth, max_depth)
        elif char == ']':
            if not depth:
                return -1  # edge case: closing bracket before opening
            depth -= 1
    return max_depth or 0  # for an empty string
